def process(text, old, new):
    if text is None:
        return ''
    old_str = str(old) if old is not None else ''
    new_str = str(new) if new is not None else ''
    return str(text).replace(old_str, new_str)

def process(text, delimiter):
    if text is None:
        return ''
    delim = str(delimiter) if delimiter is not None else ' '
    parts = str(text).split(delim)
    return str(parts)
